"use client";

import { useState, useEffect, useRef } from "react";
import Link from "next/link";

type Product = { id: number; name: string; price: number; category: string; unit: string; in_stock: number };
type CartItem = { product: Product; quantity: number };

export default function StorePage() {
  const [products, setProducts] = useState<Product[]>([]);
  const [categories, setCategories] = useState<string[]>([]);
  const [selectedCategory, setSelectedCategory] = useState("All");
  const [search, setSearch] = useState("");
  const [cart, setCart] = useState<CartItem[]>([]);
  const cartLoaded = useRef(false);

  useEffect(() => {
    const saved = localStorage.getItem("lucky_cart");
    if (saved) { try { setCart(JSON.parse(saved)); } catch { /* */ } }
    cartLoaded.current = true;
  }, []);

  useEffect(() => { if (cartLoaded.current) localStorage.setItem("lucky_cart", JSON.stringify(cart)); }, [cart]);
  useEffect(() => { fetch("/api/categories").then(r => r.json()).then(setCategories); fetch("/api/products").then(r => r.json()).then(setProducts); }, []);

  const filtered = products.filter(p => (selectedCategory === "All" || p.category === selectedCategory) && (!search || p.name.toLowerCase().includes(search.toLowerCase())));
  const cartCount = cart.reduce((s, i) => s + i.quantity, 0);
  const cartTotal = cart.reduce((s, i) => s + i.product.price * i.quantity, 0);

  function addToCart(product: Product) {
    setCart(prev => {
      const e = prev.find(i => i.product.id === product.id);
      if (e) return prev.map(i => i.product.id === product.id ? { ...i, quantity: i.quantity + 1 } : i);
      return [...prev, { product, quantity: 1 }];
    });
  }

  function removeFromCart(id: number) {
    setCart(prev => {
      const e = prev.find(i => i.product.id === id);
      if (e && e.quantity > 1) return prev.map(i => i.product.id === id ? { ...i, quantity: i.quantity - 1 } : i);
      return prev.filter(i => i.product.id !== id);
    });
  }

  const getQty = (id: number) => cart.find(i => i.product.id === id)?.quantity || 0;

  const grouped: Record<string, Product[]> = {};
  for (const p of filtered) { if (!grouped[p.category]) grouped[p.category] = []; grouped[p.category].push(p); }

  return (
    <div className="min-h-screen">
      <header className="header">
        <div className="max-w-lg mx-auto px-4 py-3 flex items-center justify-between">
          <h1 className="text-xl font-bold">Lucky Store</h1>
          <Link href="/cart" className="relative btn btn-ghost !bg-white !text-[var(--c-emerald)] !border-0 px-4 py-1.5 rounded-full text-sm">
            Cart
            {cartCount > 0 && (
              <span className="absolute -top-2 -right-2 bg-red-500 text-white text-xs w-5 h-5 rounded-full flex items-center justify-center">{cartCount}</span>
            )}
          </Link>
        </div>
      </header>

      <main className="max-w-lg mx-auto px-4 pb-24">
        <div className="mt-4">
          <input type="text" placeholder="Search for atta, milk, eggs..." value={search} onChange={e => setSearch(e.target.value)} className="input" />
        </div>

        <div className="flex gap-2 mt-4 overflow-x-auto pb-2">
          {["All", ...categories].map(cat => (
            <button key={cat} onClick={() => setSelectedCategory(cat)} className={`pill ${selectedCategory === cat ? "pill-active" : "pill-inactive"}`}>
              {cat}
            </button>
          ))}
        </div>

        {Object.entries(grouped).map(([category, prods]) => (
          <div key={category} className="mt-6 animate-in">
            <h2 className="text-lg font-bold text-gray-800 mb-3">{category}</h2>
            <div className="grid grid-cols-2 gap-3">
              {prods.map(product => {
                const qty = getQty(product.id);
                const oos = !product.in_stock;
                return (
                  <div key={product.id} className={`card p-3 ${oos ? "opacity-50" : ""}`}>
                    <div className="h-14 flex items-center justify-center text-3xl">{getCategoryEmoji(product.category)}</div>
                    <h3 className="text-sm font-medium text-gray-800 leading-tight min-h-[2.5rem] mt-1">{product.name}</h3>
                    <div className="flex items-center justify-between mt-1">
                      <span className="text-price font-bold">&#8377;{product.price}</span>
                      <span className="text-xs text-gray-400">/{product.unit}</span>
                    </div>
                    <div className="mt-2 h-9">
                      {oos ? (
                        <div className="h-full flex items-center justify-center text-red-500 text-xs font-medium">Out of Stock</div>
                      ) : qty === 0 ? (
                        <button onClick={() => addToCart(product)} className="btn btn-ghost w-full h-full text-sm">ADD</button>
                      ) : (
                        <div className="qty-stepper h-full">
                          <button onClick={() => removeFromCart(product.id)}>-</button>
                          <span>{qty}</span>
                          <button onClick={() => addToCart(product)}>+</button>
                        </div>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        ))}

        {filtered.length === 0 && <div className="text-center text-gray-400 mt-12">No products found</div>}
      </main>

      {cartCount > 0 && (
        <div className="fixed bottom-0 left-0 right-0 z-50 animate-slide-up">
          <div className="frosted-dark">
            <Link href="/cart" className="block">
              <div className="max-w-lg mx-auto px-4 py-4 flex items-center justify-between text-white">
                <div><span className="font-bold">{cartCount} item{cartCount > 1 ? "s" : ""}</span><span className="mx-2 opacity-50">|</span><span className="font-bold">&#8377;{cartTotal}</span></div>
                <span className="font-semibold">View Cart &rarr;</span>
              </div>
            </Link>
          </div>
        </div>
      )}
    </div>
  );
}

function getCategoryEmoji(c: string) {
  return { Dairy: "\uD83E\uDD5B", Eggs: "\uD83E\uDD5A", "Atta & Rice": "\uD83C\uDF3E", "Dal & Pulses": "\uD83E\uDED8", "Oil & Ghee": "\uD83C\uDFFA", Spices: "\uD83C\uDF36\uFE0F", Snacks: "\uD83C\uDF5F", Beverages: "\uD83E\uDD64", Bread: "\uD83C\uDF5E", Household: "\uD83E\uDDF9" }[c] || "\uD83D\uDED2";
}
